                      <>
                        <div className="absolute left-0 right-0 bg-black/55 pointer-events-none" style={{ top: 0, height: rt }} />
                        <div className="absolute left-0 right-0 bg-black/55 pointer-events-none" style={{ top: rb, bottom: 0 }} />
